# Dagsap App - Project Setup Wizard (PowerShell)\n# Colors and formatting for Windows PowerShell\n\nfunction Write-ColorOutput([string]$message, [string]$color) {\n    Write-Host $message -ForegroundColor $color\n}\n\nfunction Write-Banner {\n    Write-ColorOutput \"`n╔═══════════════════════════════════════════════════╗\" \"Blue\"\n    Write-ColorOutput \"║  🚀 Dagsap App - Project Setup Wizard  🚀         ║\" \"Blue\"\n    Write-ColorOutput \"║  Bootstrap your new awesome project!             ║\" \"Blue\"\n    Write-ColorOutput \"╚═══════════════════════════════════════════════════╝\" \"Blue\"\n    Write-ColorOutput \"\"\n}\n\nfunction Update-PackageJson([string]$filePath, [string]$appName, [string]$type) {\n    if (Test-Path $filePath) {\n        $content = Get-Content $filePath -Raw\n        \n        if ($type -eq \"backend\") {\n            $content = $content -replace '\"name\": \"dagsap-app-backend\"', \"\\\"name\\\": \\\"$($appName.ToLower())-backend\\\"\"\n            $content = $content -replace '\"description\": \"Dagsap JNT Internal App - Backend API with Express, Sequelize, and MySQL\"', \"\\\"description\\\": \\\"$appDescription - Backend API\\\"\"\n        } else {\n            $content = $content -replace '\"name\": \"dagsap-app-frontend\"', \"\\\"name\\\": \\\"$($appName.ToLower())-frontend\\\"\"\n            $content = $content -replace '\"description\": \"Dagsap JNT Internal App - Frontend UI with React and Vite\"', \"\\\"description\\\": \\\"$appDescription - Frontend UI\\\"\"\n        }\n        \n        $content | Set-Content $filePath\n        return $true\n    }\n    return $false\n}\n\n# Main Script\ncls\nWrite-Banner\n\nWrite-ColorOutput \"📝 Let's set up your project!\" \"Cyan\"\nWrite-ColorOutput \"\"\n\n# Get App Name\n$appName = Read-Host \"Enter your app name (e.g., MyAwesomeApp)\"\nif ([string]::IsNullOrEmpty($appName)) {\n    $appName = \"MyApp\"\n}\n\n# Get Description\n$appDescription = Read-Host \"Enter project description\"\nif ([string]::IsNullOrEmpty($appDescription)) {\n    $appDescription = \"A modern web application\"\n}\n\n# Confirm settings\nWrite-ColorOutput \"\"\nWrite-ColorOutput \"✨ Project Settings:\" \"Cyan\"\nWrite-ColorOutput \"  Name: $appName\" \"Green\"\nWrite-ColorOutput \"  Description: $appDescription\" \"Green\"\nWrite-ColorOutput \"\"\n\n$confirm = Read-Host \"Continue? (y/n)\"\nif ($confirm -ne \"y\" -and $confirm -ne \"Y\") {\n    Write-ColorOutput \"❌ Setup cancelled\" \"Red\"\n    exit 1\n}\n\nWrite-ColorOutput \"\"\nWrite-ColorOutput \"⚙️  Setting up your project...\" \"Cyan\"\nWrite-ColorOutput \"\"\n\n# Update package.json files\nWrite-ColorOutput \"→ Updating package.json files...\" \"Yellow\"\n\nif (Update-PackageJson \"server/package.json\" $appName \"backend\") {\n    Write-ColorOutput \"  ✓ server/package.json updated\" \"Green\"\n}\n\nif (Update-PackageJson \"client/package.json\" $appName \"frontend\") {\n    Write-ColorOutput \"  ✓ client/package.json updated\" \"Green\"\n}\n\n# Create environment files\nWrite-ColorOutput \"→ Creating environment files...\" \"Yellow\"\n\nif ((Test-Path \"server/.env.example\") -and -not (Test-Path \"server/.env\")) {\n    Copy-Item \"server/.env.example\" \"server/.env\"\n    Write-ColorOutput \"  ✓ server/.env created from .env.example\" \"Green\"\n}\n\nif ((Test-Path \"client/.env.example\") -and -not (Test-Path \"client/.env\")) {\n    Copy-Item \"client/.env.example\" \"client/.env\"\n    Write-ColorOutput \"  ✓ client/.env created from .env.example\" \"Green\"\n}\n\n# Install dependencies\nWrite-ColorOutput \"\"\nWrite-ColorOutput \"→ Installing dependencies...\" \"Yellow\"\n\nif ((Test-Path \"server\") -and (Test-Path \"server/package.json\")) {\n    Write-ColorOutput \"  Installing backend dependencies...\" \"Cyan\"\n    Set-Location server\n    npm install\n    Set-Location ..\n    Write-ColorOutput \"  ✓ Backend dependencies installed\" \"Green\"\n}\n\nif ((Test-Path \"client\") -and (Test-Path \"client/package.json\")) {\n    Write-ColorOutput \"  Installing frontend dependencies...\" \"Cyan\"\n    Set-Location client\n    npm install\n    Set-Location ..\n    Write-ColorOutput \"  ✓ Frontend dependencies installed\" \"Green\"\n}\n\n# Clean up unnecessary files\nWrite-ColorOutput \"\"\nWrite-ColorOutput \"→ Cleaning up template files...\" \"Yellow\"\n\n# Remove .gitkeep files\nGet-ChildItem -Path . -Recurse -Name \".gitkeep\" -ErrorAction SilentlyContinue | ForEach-Object {\n    Remove-Item (Join-Path . $_) -ErrorAction SilentlyContinue\n}\nWrite-ColorOutput \"  ✓ .gitkeep files removed\" \"Green\"\n\n# Remove template summary\nif (Test-Path \"TEMPLATE_SUMMARY.md\") {\n    Remove-Item \"TEMPLATE_SUMMARY.md\"\n    Write-ColorOutput \"  ✓ TEMPLATE_SUMMARY.md removed\" \"Green\"\n}\n\nif (Test-Path \"START_HERE.md\") {\n    Remove-Item \"START_HERE.md\"\n    Write-ColorOutput \"  ✓ START_HERE.md removed\" \"Green\"\n}\n\n# Success message\nWrite-ColorOutput \"\"\nWrite-ColorOutput \"═══════════════════════════════════════════════════\" \"Blue\"\nWrite-ColorOutput \"✨ Setup Complete! Your project is ready! ✨\" \"Green\"\nWrite-ColorOutput \"═══════════════════════════════════════════════════\" \"Blue\"\nWrite-ColorOutput \"\"\n\nWrite-ColorOutput \"📚 Next Steps:\" \"Cyan\"\nWrite-ColorOutput \"  1. Configure your database in server/.env\" \"Yellow\"\nWrite-ColorOutput \"  2. Run backend: cd server && npm run dev\" \"Yellow\"\nWrite-ColorOutput \"  3. Run frontend: cd client && npm run dev\" \"Yellow\"\nWrite-ColorOutput \"  4. Read SETUP.md for detailed instructions\" \"Yellow\"\nWrite-ColorOutput \"\"\nWrite-ColorOutput \"🚀 Happy Coding!\" \"Cyan\"\nWrite-ColorOutput \"\"\n